compliant:
#include <security/pam_appl.h>

int authenticate(const char* username, const char* password) {
    pam_handle_t* pamh = NULL;
    int retval;

    retval = pam_start("myapp", username, NULL, &pamh);
    if (retval == PAM_SUCCESS) {
        retval = pam_authenticate(pamh, 0);

        // Compliant - check account validity
        if (retval == PAM_SUCCESS) {
            retval = pam_acct_mgmt(pamh, 0);  // Verify account validity
        }
    }

    pam_end(pamh, retval);
    return retval;
}
